```class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length / 2;
        int res = 0;
        for (int i = 0; i < row.length; i += 2) {
            if (row[i] % 2 != row[i + 1] % 2) {
                int j = i + 1;
                while (row[j] % 2 != row[i] % 2) {
                    j++;
                }
                int temp = row[j];
                row[j] = row[i + 1];
                row[i + 1] = temp;
                res++;
            }
        }
        return res;
    }
}```
